1	const PROCESSING_FEE = 5;
2	const DEFAULT_BASE_PREMIUM = 100;
3	const CURSE_SURCHARGE_RATE = 0.5;
4	const FIRST_INSURANCE_RATE = 0.1;
5	const HIGH_ENCHANTMENT_RATE = 0.3;
6	const HIGH_ENCHANTMENT_THRESHOLD = 5;
7	const LOYALTY_DISCOUNT_RATE = 0.2;
8	const LOYALTY_THRESHOLD_YEARS = 2;
9	
10	type QuoteItem = { type: string; material?: string; enchantment?: number; cursed?: boolean };
11	type Step = { op: string; items: QuoteItem[] };
12	type Customer = { yearsWithMHPCO: number };
13	type Scenario = { customer: Customer; steps: Step[] };
14	
15	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
16	  amulet: 60,
17	  rune: 25,
18	  moonstone: 25,
19	};
20	const BLOCK_TYPES = new Set(["rune", "moonstone"]);
21	const BLOCK_OF_THREE_BASE = 60;
22	const BLOCK_SIZE = 3;
23	
24	const basePremiumForItem = (item: QuoteItem): number =>
25	  BASE_PREMIUM_BY_TYPE[item.type] ?? DEFAULT_BASE_PREMIUM;
26	
27	const groupByType = (items: QuoteItem[]): Map<string, QuoteItem[]> =>
28	  items.reduce((groups, item) => {
29	    const group = groups.get(item.type) ?? [];
30	    return groups.set(item.type, [...group, item]);
31	  }, new Map<string, QuoteItem[]>());
32	
33	const isHighEnchantment = (item: QuoteItem): boolean =>
34	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
35	
36	const itemSurchargeRate = (item: QuoteItem): number =>
37	  (item.cursed ? CURSE_SURCHARGE_RATE : 0) +
38	  (isHighEnchantment(item) ? HIGH_ENCHANTMENT_RATE : 0) +
39	  FIRST_INSURANCE_RATE;
40	
41	const itemPremium = (item: QuoteItem): number => {
42	  const base = basePremiumForItem(item);
43	  return base + base * itemSurchargeRate(item);
44	};
45	
46	const isBlockGroup = (type: string, group: QuoteItem[]): boolean =>
47	  BLOCK_TYPES.has(type) && group.length === BLOCK_SIZE;
48	
49	const groupBase = (type: string, group: QuoteItem[]): number =>
50	  isBlockGroup(type, group)
51	    ? BLOCK_OF_THREE_BASE
52	    : group.reduce((sum, item) => sum + basePremiumForItem(item), 0);
53	
54	const groupPremium = (type: string, group: QuoteItem[]): number =>
55	  isBlockGroup(type, group)
56	    ? BLOCK_OF_THREE_BASE * (1 + FIRST_INSURANCE_RATE)
57	    : group.reduce((sum, item) => sum + itemPremium(item), 0);
58	
59	const sumOver = (
60	  items: QuoteItem[],
61	  groupFn: (type: string, group: QuoteItem[]) => number,
62	): number =>
63	  [...groupByType(items)].reduce(
64	    (total, [type, group]) => total + groupFn(type, group),
65	    0,
66	  );
67	
68	const loyaltyDiscount = (customer: Customer, policyBase: number): number =>
69	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? policyBase * LOYALTY_DISCOUNT_RATE : 0;
70	
71	const quoteStep = (customer: Customer) => (step: Step) => ({
72	  premium:
73	    sumOver(step.items, groupPremium) -
74	    loyaltyDiscount(customer, sumOver(step.items, groupBase)) +
75	    PROCESSING_FEE,
76	});
77	
78	export const runScenario = (scenario: unknown): unknown => {
79	  const { customer, steps } = scenario as Scenario;
80	  return { results: steps.map(quoteStep(customer)) };
81	};
